function premises_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('premises');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'premises_name' => Request::val('premises_name', ''),
		'premises_latitude' => Request::val('premises_latitude', ''),
		'premises_longitude' => Request::val('premises_longitude', ''),
		'premises_radius' => Request::val('premises_radius', ''),
		'premises_opening' => Request::lookup('premises_opening', ''),
		'premises_closing' => Request::lookup('premises_closing', ''),
		'premises_created' => parseCode('<%%creationTimestamp%%>', true, true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('premises', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		premises_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function premises_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

