function premises_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('premises', $selected_id, 'edit')) return false;

	$data = [
		'premises_name' => Request::val('premises_name', ''),
		'premises_latitude' => Request::val('premises_latitude', ''),
		'premises_longitude' => Request::val('premises_longitude', ''),
		'premises_radius' => Request::val('premises_radius', ''),
		'premises_opening' => Request::lookup('premises_opening', ''),
		'premises_closing' => Request::lookup('premises_closing', ''),
		'premises_updated' => parseCode('<%%editingTimestamp%%>', false, true),
	];

	if($data['premises_name'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Premise Name': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	if($data['premises_latitude'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Latitude': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	if($data['premises_longitude'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Longitude': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	if($data['premises_radius'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Premises radius': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	// get existing values
	$old_data = getRecord('premises', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: premises_before_update
	if(function_exists('premises_before_update')) {
		$args = ['old_data' => $old_data];
		if(!premises_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'premises',
		backtick_keys_once($set),
		['`premises_id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="premises_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('premises', $data['selectedID'], calculated_fields()['premises']);

	// hook: premises_after_update
	if(function_exists('premises_after_update')) {
		if($row = getRecord('premises', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['premises_id'];
		$args = ['old_data' => $old_data];
		if(!premises_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('premises', $selected_id);
}

function premises_form($selectedId = '', $allowUpdate = true, $allowInsert = true, $allowDelete = true, $separateDV = true, $templateDV = '', $templateDVP = '') {
	// function to return an editable form for a table records
	// and fill it with data of record whose ID is $selectedId. If $selectedId
